def _deep_hash(d: Dict[str, Any]) -> str:
    "SHA-256 over canonical JSON (sort keys, no spaces)."
    return hashlib.sha256(
        json.dumps(d, sort_keys=True, separators=(",", ":")).encode()
    ).hexdigest()

